import pytest
from playwright.sync_api import Page
from axe_playwright_python.sync_playwright import Axe

BASE_URL = "http://localhost:3000"

@pytest.fixture(scope="function")
def page(browser):
    ctx = browser.new_context()
    pg = ctx.new_page()
    yield pg
    ctx.close()

def test_low_contrast_element_triggers_violation(page: Page):
    page.goto(f"{BASE_URL}/login", wait_until="networkidle")
    page.evaluate(
        """
        () => {
          const el = document.createElement('p');
          el.id = 'injected-low-contrast';
          el.textContent = 'Low contrast test text';
          el.style.color = '#aaaaaa';
          el.style.backgroundColor = '#ffffff';
          el.style.fontSize = '14px';
          document.body.appendChild(el);
        }
        """
    )
    axe = Axe()
    results = axe.run(
        page,
        options={"runOnly": {"type": "rule", "values": ["color-contrast"]}}
    )
    violation_ids = [v["id"] for v in results.violations]
    assert "color-contrast" in violation_ids, (
        f"Expected color-contrast violation not found. Got: {violation_ids}"
    )
    cc_violation = next(v for v in results.violations if v["id"] == "color-contrast")
    assert cc_violation["impact"] in ("serious", "critical")

import pytest
from playwright.sync_api import Page
from axe_playwright_python.sync_playwright import Axe

BASE_URL = "http://localhost:3000"

@pytest.fixture(scope="function")
def page(browser):
    ctx = browser.new_context()
    pg = ctx.new_page()
    yield pg
    ctx.close()

def test_contrast_ratio_at_aa_boundary_45_to_1(page: Page):
    page.goto(f"{BASE_URL}/settings", wait_until="networkidle")
    # #767676 on #ffffff ≈ 4.54:1 (passes); #777777 on #ffffff ≈ 4.48:1 (fails)
    page.evaluate(
        """
        () => {
          ['passing-contrast', 'failing-contrast'].forEach((id, i) => {
            const el = document.createElement('p');
            el.id = id;
            el.textContent = 'Boundary contrast text';
            el.style.color = i === 0 ? '#767676' : '#777777';
            el.style.backgroundColor = '#ffffff';
            el.style.fontSize = '14px';
            document.body.appendChild(el);
          });
        }
        """
    )
    computed_ratio = <helper_fn:compute_contrast_ratio>(page, "#passing-contrast")
    assert 4.45 <= computed_ratio <= 4.65, (
        f"Expected ratio ~4.5 for passing element, got {computed_ratio}"
    )
    axe = Axe()
    results = axe.run(
        page,
        options={"runOnly": {"type": "rule", "values": ["color-contrast"]}}
    )
    failing_nodes = <helper_fn:extract_violation_node_ids>(results, "color-contrast")
    assert "passing-contrast" not in failing_nodes, (
        "Element at 4.5:1 should NOT be flagged as a violation"
    )
    assert "failing-contrast" in failing_nodes, (
        "Element at 4.49:1 SHOULD be flagged as a violation"
    )
